#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <stdlib.h>
#include <string.h>

#define BUFFER_SIZE 1024

int main(int argc, char *argv[]) {
 if (argc != 2) {
 fprintf(stderr, "Usage: %s <filename>\n", argv[0]);
 return 1;
 }

 // Open file: returns -1 on failure
 int fd = open(argv[1], O_RDONLY);
 if (fd == -1) {
 perror("open failed"); // Prints "open failed: <error message>"
 return 1;
 }

 char buffer[BUFFER_SIZE];
 ssize_t bytes_read;

 // Read in loop until EOF or error
 while ((bytes_read = read(fd, buffer, BUFFER_SIZE)) > 0) {
 // Write to stdout
 if (write(STDOUT_FILENO, buffer, bytes_read) == -1) {
 perror("write failed");
 close(fd);
 return 1;
 }
 }

 if (bytes_read == -1) {
 perror("read failed");
 close(fd);
 return 1;
 }

 // Close file descriptor
 if (close(fd) == -1) {
 perror("close failed");
 return 1;
 }

 return 0;
}

#include <unistd.h>
#include <fcntl.h>
#include <stdio.h>

/*
 * Standard File Descriptors:
 * 0 = STDIN - Standard Input (read from keyboard/file)
 * 1 = STDOUT - Standard Output (write to terminal/file)
 * 2 = STDERR - Standard Error (write error messages)
 *
 * These are constants defined in <unistd.h> as:
 * #define STDIN_FILENO 0
 * #define STDOUT_FILENO 1
 * #define STDERR_FILENO 2
 */

int main() {
 // Writing to STDOUT (file descriptor 1)
 const char *msg = "Hello, Unix System Programming!\n";
 write(STDOUT_FILENO, msg, 35);

 // Writing error message to STDERR (file descriptor 2)
 const char *err = "This is an error message\n";
 write(STDERR_FILENO, err, 26);

 // Demonstrating redirect: when stdout is redirected to a file,
 // STDOUT_FILENO (1) points to the file, not terminal
 // STDERR (2) still shows on terminal for error visibility

 return 0;
}

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>
#include <stdlib.h>

void handle_open_error(const char *filename) {
 fprintf(stderr, "Failed to open '%s': %s\n", 
 filename, strerror(errno));

 // Handle specific errors differently
 switch (errno) {
 case ENOENT:
 fprintf(stderr, "-> The file does not exist.\n");
 break;
 case EACCES:
 fprintf(stderr, "-> Permission denied.\n");
 break;
 case EISDIR:
 fprintf(stderr, "-> Is a directory, not a file.\n");
 break;
 default:
 fprintf(stderr, "-> Unknown error code: %d\n", errno);
 }
}

int main(int argc, char *argv[]) {
 if (argc < 2) {
 fprintf(stderr, "Usage: %s <filename>\n", argv[0]);
 return 1;
 }

 int fd = open(argv[1], O_RDONLY);
 if (fd == -1) {
 handle_open_error(argv[1]);
 return 1;
 }

 printf("Successfully opened: %s (fd=%d)\n", argv[1], fd);
 close(fd);
 return 0;
}
